// Module generated by assisting assistant for async_filo implementation
module async_filo(

    // Module parameters
    parameter DATA_WIDTH = 8,
    parameter DEPTH = 8,

    // Module ports
    input            w_clk,
    input            w_rst,
    input            push,
    input            r_rst,
    input            r_clk,
    output           w_data,
    output           r_data,
    output           r_empty,
    output           w_full
)

// Helpers for Gray code conversion
function bit [depth-1:0] gray2bin(bit [depth-1:0] g);
    bit [depth-1:0] b = g;
    for (int i = 0; i < depth; i++) {
        if (i > 0) {
            b[i] ^= b[i+1];
        }
    }
    return b;
endfunction

function bit [depth-1:0] bin2gray(bit [depth-1:0] b);
    bit [depth-1:0] g = b;
    for (int i = 0; i < depth; i++) {
        if (i > 0) {
            g[i] ^= g[i-1];
        }
    }
    return g;
endfunction

// Internal state variables
reg [DATA_WIDTH-1:0] w_data;
reg [DATA_WIDTH-1:0] r_data;
wire [DATA_WIDTH-1:0] r_data;
wire r_empty;
wire w_full;

// Internal memory
bit [DATA_WIDTH-1:0] mem[DEPTH];

// Write pointer (Gray coded)
bit [DATA_WIDTH-1:0] w_ptr;
bit [DATA_WIDTH-1:0] w_ptr_binary;

// Read pointer (Gray coded)
bit [DATA_WIDTH-1:0] r_ptr;
bit [DATA_WIDTH-1:0] r_ptr_binary;

// State variables
always_comb
    w_ptr_binary = bin2gray(w_ptr);
    r_ptr_binary = bin2gray(r_ptr);

// Synchronize read pointer from write domain
always_posedge w_clk begin
    if (w_rst) begin
        w_ptr = 0;
        w_ptr_binary = 0;
        w_full = 0;
        r_empty = 1;
        $display("Initialization complete.");
    end
    // Ensure proper pointer updates happen only once per transition
    if ($prev(w_rst)) begin
        w_ptr++;
        w_ptr_binary = bin2gray(w_ptr);
    end
end

// Synchronize write pointer from read domain
always_negedge r_clk begin
    if (r_rst) begin
        r_ptr = 0;
        r_ptr_binary = 0;
        w_full = 1;
        r_empty = 0;
        $display("Initialization complete.");
    end
    // Ensure proper pointer updates happen only once per transition
    if ($prev(r_rst)) begin
        r_ptr++;
        r_ptr_binary = bin2gray(r_ptr);
    end
end

// Process block for push operation
process (w_clk)
begin
    if (w_rst) begin
        w_rst = 0;
        w_full = 0;
        r_empty = 1;
        $display("Initialization complete.");
    end
    repeat (DEPTH) begin
        if (~w_full && push) begin
            w_data = $input();
            mem[w_ptr] = w_data;
            w_ptr++;
            w_full = (w_ptr == DEPTH);
            w_rst = 0;
            r_empty = 0;
            $display("Data pushed successfully.");
            break;
        end
        @(posedge w_clk);
        w_rst = 1;
        $display("Waiting for data to be pushed.");
    end
end

// Process block for pop operation
process (r_clk)
begin
    if (r_rst) begin
        r_rst = 0;
        r_empty = 0;
        w_full = 1;
        $display("Initialization complete.");
    end
    repeat (DEPTH) begin
        if (~r_empty && pop) begin
            r_data = mem[r_ptr];
            r_ptr--;
            r_empty = (r_ptr == -1);
            r_rst = 0;
            w_full = 0;
            $display("Data popped successfully.");
            break;
        end
        @(posedge r_clk);
        r_rst = 1;
        $display("Waiting for data to be popped.");
    end
end